    bool judgeCircle(string moves) {
        vector<int> x_coordinates(2 * 1000000, 0); // Initialize an array to store the x coordinates
        vector<int> y_coordinates(2 * 1000000, 0); // Initialize another array to store the y coordinates

        for (char move : moves) { // Iterate over the given moves
            int x_diff = 0, y_diff = 0; // Initialize x and y differences

            if (move == 'U') { // Check if the move is up
                y_diff = 1;
            } else if (move == 'D') { // Check if the move is down
                y_diff = -1;
            } else if (move == 'L') { // Check if the move is left
                x_diff = -1;
            } else { // Check if the move is right
                x_diff = 1;
            }

            x_coordinates[x_diff * 2 + 1] += y_diff; // Update the corresponding coordinates in the arrays
        }

        return x_coordinates[0] == 0 && y_coordinates[0] == 0; // Return true if the robot ends up at (0, 0)
}
